pub fn next_token(&mut self) -> &str {
    let start = self.pos;
    while self.pos < self.input.len() {
        if self.input.as_bytes()[self.pos] == b' ' {
            break;
        }
        self.pos += 1;
    }
    let end = self.pos;
    self.pos = (self.pos + 1).min(self.input.len()); // skip space, clamp
    &self.input[start..end]
}
